-- ============================================================
-- GUI PATCH: Applies visual & text changes after GUI renders
-- ============================================================
task.spawn(function()
    task.wait(0.6) -- Wait for GUI to be fully built

    local function patchDescendants(parent)
        for _, obj in ipairs(parent:GetDescendants()) do

            -- ── Text changes ─────────────────────────────────
            if obj:IsA("TextLabel") or obj:IsA("TextButton") then

                -- Rename hub title
                if obj.Text:find("Jawa Hub") then
                    obj.Text = obj.Text:gsub("Jawa Hub", "Rama Hub")
                end

                -- Rename MS Sudah Jadi → Marshmellow
                if obj.Text:lower():find("ms sudah jadi") or obj.Text:lower():find("ms sudah jadi:") then
                    obj.Text = obj.Text:gsub("[Mm][Ss]%s+[Ss]udah%s+[Jj]adi", "Marshmellow")
                end

                -- "Start AutoMS" button → blue
                if obj.Text == "Start AutoMS" then
                    obj.BackgroundColor3 = Color3.fromRGB(30, 100, 220)
                    obj.TextColor3      = Color3.fromRGB(255, 255, 255)
                end
            end

            -- ── Background color changes ──────────────────────
            if obj:IsA("Frame") or obj:IsA("ScrollingFrame") then
                local c  = obj.BackgroundColor3
                local r  = math.round(c.R * 255)
                local g  = math.round(c.G * 255)
                local b  = math.round(c.B * 255)
                -- If colour is very dark (near black), replace with lighter blue
                if r <= 40 and g <= 40 and b <= 40 then
                    obj.BackgroundColor3 = Color3.fromRGB(28, 52, 105)
                end
            end

        end
    end

    -- ── Insert "Ingredients" label above Water row ──────────
    local function addIngredientsLabel(parent)
        for _, obj in ipairs(parent:GetDescendants()) do
            if obj:IsA("TextLabel") then
                local txt = obj.Text or ""
                -- Detect the Water label (handles "Water: 0", "Water:0", etc.)
                if txt:match("^Water") then
                    local frame = obj.Parent
                    if frame and not frame:FindFirstChild("RamaIngredientsHeader") then
                        local lbl = Instance.new("TextLabel")
                        lbl.Name               = "RamaIngredientsHeader"
                        lbl.Text               = "Ingredients"
                        lbl.Font               = obj.Font
                        lbl.TextSize           = obj.TextSize
                        lbl.TextColor3         = Color3.fromRGB(255, 200, 50)
                        lbl.BackgroundTransparency = 1
                        lbl.TextXAlignment     = obj.TextXAlignment
                        lbl.Size               = UDim2.new(
                            obj.Size.X.Scale, obj.Size.X.Offset,
                            obj.Size.Y.Scale, obj.Size.Y.Offset
                        )
                        -- Place it directly above the Water label
                        lbl.Position = UDim2.new(
                            obj.Position.X.Scale,
                            obj.Position.X.Offset,
                            obj.Position.Y.Scale,
                            obj.Position.Y.Offset - obj.AbsoluteSize.Y - 4
                        )
                        lbl.Parent = frame
                    end
                end
            end
        end
    end

    -- Apply patch to all GUI containers
    local targets = {}
    pcall(function() table.insert(targets, game:GetService("CoreGui")) end)
    pcall(function() table.insert(targets, game.Players.LocalPlayer.PlayerGui) end)

    for _, svc in ipairs(targets) do
        pcall(function() patchDescendants(svc) end)
        pcall(function() addIngredientsLabel(svc) end)
    end
end)
